type ErrorCodeDescription (errorCode: string, shortDescription: string, description: string) =
    member _.ErrorCode: string = errorCode
    member _.ShortDescription: string = shortDescription
    member _.Description: string = description


let getErrorCodeDescription (errorCode: int): ErrorCodeDescription =
    let shortDescription, description: string * string =
        try lookupTable |> HashMap.find errorCode with
        | _ -> let tmp: string = "Unknown error code" in tmp, tmp

    ErrorCodeDescription ($"FS%04d{errorCode}", shortDescription, description)